  8Ôćĺ/**
  9Ôćĺ * Extract repository name from URL for display
 10Ôćĺ * Handles any Git repository URL: GitHub, GitLab, Bitbucket, self-hosted
 11Ôćĺ * Supports HTTPS and SSH formats
 12Ôćĺ * Returns: "owner/repo" format
 13Ôćĺ *
 14Ôćĺ * Examples:
 15Ôćĺ * - https://github.com/owner/repo -> "owner/repo"
 16Ôćĺ * - git@gitlab.com:owner/repo.git -> "owner/repo"
 17Ôćĺ * - https://git.company.com/owner/repo -> "owner/repo"
 18Ôćĺ */
 19Ôćĺexport function extractRepoName(url: string): string {
 20Ôćĺ	try {
 21Ôćĺ		// Handle SSH format: git@domain:owner/repo.git
 22Ôćĺ		if (url.startsWith("git@")) {
 23Ôćĺ			const sshMatch = url.match(/git@[^:]+:(.+?)(?:\.git)?$/);
 24Ôćĺ			if (sshMatch) {
 25Ôćĺ				const path = sshMatch[1];
 26Ôćĺ				const pathParts = path.split("/");
 27Ôćĺ				// For nested paths (e.g., group/subgroup/project), take first and last
 28Ôćĺ				if (pathParts.length >= 2) {
 29Ôćĺ					return `${pathParts[0]}/${pathParts[pathParts.length - 1]}`;
 30Ôćĺ				}
 31Ôćĺ			}
 32Ôćĺ		}
 33Ôćĺ
 34Ôćĺ		// Handle HTTPS format: https://domain.com/owner/repo
 35Ôćĺ		if (url.startsWith("http://") || url.startsWith("https://")) {
 36Ôćĺ			const urlObj = new URL(url);
 37Ôćĺ			const pathParts = urlObj.pathname.split("/").filter(Boolean);
 38Ôćĺ
 39Ôćĺ			// Remove .git suffix from last part if present
 40Ôćĺ			if (pathParts.length >= 2) {
 41Ôćĺ				const lastPart = pathParts[pathParts.length - 1].replace(/\.git$/, "");
 42Ôćĺ				return `${pathParts[0]}/${lastPart}`;
 43Ôćĺ			}
 44Ôćĺ		}
 45Ôćĺ
 46Ôćĺ		// Fallback: try to extract pathname
 47Ôćĺ		const urlObj = new URL(url);
 48Ôćĺ		return urlObj.pathname.replace(/^\//, "").replace(/\.git$/, "") || url;
 49Ôćĺ	} catch {
 50Ôćĺ		return url;
 51Ôćĺ	}
 52Ôćĺ}
 53Ôćĺ
 54Ôćĺ/**
 55Ôćĺ * Extract just the repository name (without owner) from URL
 56Ôćĺ * Handles any Git repository URL: GitHub, GitLab, Bitbucket, self-hosted
 57Ôćĺ * Returns: "repo" format only (without owner)
 58Ôćĺ *
 59Ôćĺ * Examples:
 60Ôćĺ * - https://github.com/owner/repo -> "repo"
 61Ôćĺ * - git@gitlab.com:owner/repo.git -> "repo"
 62Ôćĺ * - https://git.company.com/owner/repo -> "repo"
 63Ôćĺ */
 64Ôćĺexport function extractRepoNameOnly(url: string): string {
 65Ôćĺ	try {
