 67Ôćĺ		if (url.startsWith("git@")) {
 68Ôćĺ			const sshMatch = url.match(/git@[^:]+:.*\/(.+?)(?:\.git)?$/);
 69Ôćĺ			if (sshMatch) {
 70Ôćĺ				return sshMatch[1];
 71Ôćĺ			}
 72Ôćĺ		}
 73Ôćĺ
 74Ôćĺ		// Handle HTTPS format: https://domain.com/owner/repo
 75Ôćĺ		if (url.startsWith("http://") || url.startsWith("https://")) {
 76Ôćĺ			const urlObj = new URL(url);
 77Ôćĺ			const pathParts = urlObj.pathname.split("/").filter(Boolean);
 78Ôćĺ
 79Ôćĺ			if (pathParts.length >= 2) {
 80Ôćĺ				// Get last part and remove .git suffix
 81Ôćĺ				return pathParts[pathParts.length - 1].replace(/\.git$/, "");
 82Ôćĺ			}
 83Ôćĺ		}
 84Ôćĺ
 85Ôćĺ		return url;
 86Ôćĺ	} catch {
 87Ôćĺ		return url;
 88Ôćĺ	}
 89Ôćĺ}
