 91Ôćĺ/**
 92Ôćĺ * Format duration for display - short format
 93Ôćĺ * Used for: displaying total evaluation time in summaries
 94Ôćĺ * Returns: "123ms", "45.5s", or "9m 29s"
 95Ôćĺ */
 96Ôćĺexport function formatDuration(ms: number): string {
 97Ôćĺ	if (ms < 1000) {
 98Ôćĺ		return `${ms}ms`;
 99Ôćĺ	}
100Ôćĺ	const totalSeconds = ms / 1000;
101Ôćĺ	if (totalSeconds < 60) {
102Ôćĺ		return `${totalSeconds.toFixed(1)}s`;
103Ôćĺ	}
104Ôćĺ	const minutes = Math.floor(totalSeconds / 60);
105Ôćĺ	const seconds = Math.round(totalSeconds % 60);
106Ôćĺ	return `${minutes}m ${seconds}s`;
107Ôćĺ}
108Ôćĺ
109Ôćĺ/**
110Ôćĺ * Format elapsed time for display - human readable format
111Ôćĺ * Used for: showing elapsed time during evaluation progress
112Ôćĺ * Returns: "5m 30s" or "45s"
113Ôćĺ */
114Ôćĺexport function formatElapsedTime(ms: number): string {
115Ôćĺ	const seconds = Math.floor(ms / 1000);
116Ôćĺ	const minutes = Math.floor(seconds / 60);
117Ôćĺ	const remainingSeconds = seconds % 60;
118Ôćĺ
119Ôćĺ	if (minutes > 0) {
120Ôćĺ		return `${minutes}m ${remainingSeconds}s`;
121Ôćĺ	}
122Ôćĺ	return `${seconds}s`;
123Ôćĺ}
