125Ôćĺ/**
126Ôćĺ * Format relative date for display
127Ôćĺ * Used for: showing when evaluations were created in history
128Ôćĺ * Returns: "Just now", "5m ago", "2h ago", "3d ago", or "Jan 15"
129Ôćĺ */
130Ôćĺexport function formatRelativeDate(isoString: string): string {
131Ôćĺ	const date = new Date(isoString);
132Ôćĺ	const now = new Date();
133Ôćĺ	const diffMs = now.getTime() - date.getTime();
134Ôćĺ	const diffMins = Math.floor(diffMs / 60000);
135Ôćĺ	const diffHours = Math.floor(diffMs / 3600000);
136Ôćĺ	const diffDays = Math.floor(diffMs / 86400000);
137Ôćĺ
138Ôćĺ	if (diffMins < 1) return "Just now";
139Ôćĺ	if (diffMins < 60) return `${diffMins}m ago`;
140Ôćĺ	if (diffHours < 24) return `${diffHours}h ago`;
141Ôćĺ	if (diffDays < 7) return `${diffDays}d ago`;
142Ôćĺ
143Ôćĺ	return date.toLocaleDateString("en-US", {
144Ôćĺ		month: "short",
145Ôćĺ		day: "numeric",
146Ôćĺ		year: date.getFullYear() !== now.getFullYear() ? "numeric" : undefined,
147Ôćĺ	});
148Ôćĺ}
