173Ôćĺexport function getFilteredEvaluatorCount(
174Ôćĺ	filter: EvaluatorFilter,
175Ôćĺ	maxCount: number = 17,
176Ôćĺ	selectedCount?: number,
177Ôćĺ): number {
178Ôćĺ	// When specific evaluators are selected, use that count directly
179Ôćĺ	if (selectedCount !== undefined) {
180Ôćĺ		return Math.min(selectedCount, maxCount);
181Ôćĺ	}
182Ôćĺ
183Ôćĺ	// Total counts by filter type
184Ôćĺ	const COUNTS = {
185Ôćĺ		all: 17,
186Ôćĺ		errors: 13,
187Ôćĺ		suggestions: 4,
188Ôćĺ	};
189Ôćĺ
190Ôćĺ	const filteredCount = COUNTS[filter];
191Ôćĺ
192Ôćĺ	// Apply maxCount limit (in case user sets a lower limit)
193Ôćĺ	return Math.min(filteredCount, maxCount);
