435Ôćĺ	 */
436Ôćĺ	async stop(): Promise<void> {
437Ôćĺ		apiServerLogger.log("\n­čŤĹ Shutting down API server...");
438Ôćĺ
439Ôćĺ		this.remediationSSEHandler.shutdown();
440Ôćĺ		this.remediationJobManager.shutdown();
441Ôćĺ		this.sseHandler.shutdown();
