467Ôćĺexport async function startAPIServer(
468Ôćĺ	config: IAPIServerConfig = {},
469Ôćĺ): Promise<APIServer> {
470Ôćĺ	const server = new APIServer(config);
471Ôćĺ	await server.start(config);
472Ôćĺ
473Ôćĺ	// Handle graceful shutdown
474Ôćĺ	process.on("SIGINT", async () => {
