 1Ôćĺ#!/usr/bin/env bun
 2Ôćĺ
 3Ôćĺ/**
 4Ôćĺ * Main entry point for context-evaluator
 5Ôćĺ * Routes to either CLI mode or API mode based on arguments
 6Ôćĺ */
 7Ôćĺ
 8Ôćĺconst args = process.argv.slice(2);
 9Ôćĺ
10Ôćĺ// Determine mode based on first argument
11Ôćĺconst mode = args[0];
12Ôćĺ
13Ôćĺif (mode === "api") {
14Ôćĺ	// API mode - start the web server
15Ôćĺ	// Parse CLI options for API mode (--host, --port, --cloud, --daily-limit)
16Ôćĺ	let hostname = process.env.HOST ?? "localhost";
17Ôćĺ	let port = Number(process.env.PORT) || 3001;
18Ôćĺ	let cloudMode = process.env.CLOUD_MODE === "true";
19Ôćĺ	let dailyGitEvalLimit = process.env.DAILY_GIT_EVAL_LIMIT
20Ôćĺ		? Number(process.env.DAILY_GIT_EVAL_LIMIT)
21Ôćĺ		: 50;
22Ôćĺ
23Ôćĺ	// Parse --host, --port, --cloud, and --daily-limit flags from command line
24Ôćĺ	for (let i = 1; i < args.length; i++) {
25Ôćĺ		if (args[i] === "--host" && args[i + 1]) {
26Ôćĺ			hostname = args[i + 1]!;
27Ôćĺ			i++; // Skip the next argument
28Ôćĺ		} else if (args[i] === "--port" && args[i + 1]) {
29Ôćĺ			const parsedPort = Number(args[i + 1]);
30Ôćĺ			if (!isNaN(parsedPort) && parsedPort > 0 && parsedPort <= 65535) {
31Ôćĺ				port = parsedPort;
32Ôćĺ			} else {
33Ôćĺ				console.error(`Error: Invalid port number: ${args[i + 1]}`);
34Ôćĺ				process.exit(1);
35Ôćĺ			}
36Ôćĺ			i++; // Skip the next argument
37Ôćĺ		} else if (args[i] === "--cloud") {
38Ôćĺ			cloudMode = true;
39Ôćĺ		} else if (args[i] === "--daily-limit" && args[i + 1]) {
40Ôćĺ			const parsed = Number(args[i + 1]);
41Ôćĺ			if (!isNaN(parsed) && parsed > 0) {
42Ôćĺ				dailyGitEvalLimit = parsed;
43Ôćĺ			} else {
44Ôćĺ				console.error(`Error: Invalid daily limit: ${args[i + 1]}`);
45Ôćĺ				process.exit(1);
46Ôćĺ			}
47Ôćĺ			i++; // Skip the next argument
48Ôćĺ		}
49Ôćĺ	}
50Ôćĺ
51Ôćĺ	// Default to port 3001 to avoid conflict with frontend server (port 3000)
52Ôćĺ	const { startAPIServer } = await import("./api/index.ts");
53Ôćĺ	await startAPIServer({
54Ôćĺ		port,
55Ôćĺ		hostname,
56Ôćĺ		maxConcurrentJobs: process.env.MAX_CONCURRENT_JOBS
57Ôćĺ			? Number(process.env.MAX_CONCURRENT_JOBS)
58Ôćĺ			: undefined,
59Ôćĺ		maxQueueSize: process.env.MAX_QUEUE_SIZE
60Ôćĺ			? Number(process.env.MAX_QUEUE_SIZE)
61Ôćĺ			: undefined,
62Ôćĺ		enableAssessmentFeatures:
63Ôćĺ			process.env.ENABLE_ASSESSMENT_FEATURES === "true" || false,
64Ôćĺ		cloudMode,
65Ôćĺ		dailyGitEvalLimit,
66Ôćĺ	});
67Ôćĺ} else if (mode === "cli") {
68Ôćĺ	// CLI mode - pass control to CLI entry point
69Ôćĺ	// Remove 'cli' from args and pass the rest to the CLI
70Ôćĺ	process.argv = [process.argv[0]!, process.argv[1]!, ...args.slice(1)];
71Ôćĺ
72Ôćĺ	// Import and run CLI
73Ôćĺ	import("./cli/index.ts");
74Ôćĺ} else {
75Ôćĺ	// Default to CLI mode if no mode specified or unrecognized mode
76Ôćĺ	console.log("Usage:");
77Ôćĺ	console.log(
78Ôćĺ		"  bun run src/index.ts cli [command] [options]  # Run in CLI mode",
79Ôćĺ	);
80Ôćĺ	console.log(
81Ôćĺ		"  bun run src/index.ts api                       # Run in API mode (web server)",
82Ôćĺ	);
83Ôćĺ	console.log("");
84Ôćĺ	console.log("Examples:");
85Ôćĺ	console.log("  bun run src/index.ts cli evaluate --claude");
86Ôćĺ	console.log(
87Ôćĺ		"  bun run src/index.ts cli evaluate --claude --url https://github.com/...",
88Ôćĺ	);
89Ôćĺ	console.log("");
90Ôćĺ	console.log("For CLI help:");
91Ôćĺ	console.log("  bun run src/index.ts cli --help");
92Ôćĺ	console.log("");
93Ôćĺ	process.exit(1);
94Ôćĺ}
